mapper.select:
 
		 
		select 
			userid, userpw, username, regdate, updatedate, enabled
		from ( 
				select 
					 ROWNUM rn, userid, userpw, username, regdate, updatedate, enabled
				from (
						select userid, null as userpw, username, to_char(regdate,'yyyy/mm/dd') as regdate, to_char(updatedate,'yyyy/mm/dd') as updatedate, enabled
						  from cotdl.tbl_member order by regdate desc
					 ) f
				where userid != 'admin' and
		
	    
		
						
							and upper(userid) like '%'||upper(#{search1})||'%'
						
						
							and username like '%'||#{search2}||'%'
						
						
		
	    
	    
				 ROWNUM <= #{pagenum} * #{amount} 
				order by regdate desc
			  ) d
		where rn > (#{pagenum} -1) * #{amount} 
		order by regdate desc
